import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { getAllDoctors, bookAppointment } from '../services/api';
import Navbar from '../components/Navbar';

const SLOTS = ['09:00 AM','10:00 AM','11:00 AM','12:00 PM','02:00 PM','03:00 PM','04:00 PM','05:00 PM'];

const specColors = {
  Cardiology: '#dc2626',
  Neurology: '#16a34a',
  Orthopedics: '#ea580c',
  Dermatology: '#a21caf',
  Pediatrics: '#2563eb',
  'General Medicine': '#0d9488',
};

const BookAppointment = () => {
  const navigate = useNavigate();

  const [doctors, setDoctors] = useState([]);
  const [selDoc, setSelDoc] = useState('');
  const [date, setDate] = useState('');
  const [selSlot, setSelSlot] = useState('');
  const [symptoms, setSymptoms] = useState('');
  const [loading, setLoading] = useState(false);
  const [msg, setMsg] = useState({ type: '', text: '' });
  const [step, setStep] = useState(1);

  useEffect(() => {
    getAllDoctors().then(r => setDoctors(r.data)).catch(console.log);

    const pre = sessionStorage.getItem('preDoc');
    if (pre) {
      setSelDoc(pre);
      sessionStorage.removeItem('preDoc');
      setStep(2);
    }

    const today = new Date().toISOString().split('T')[0];
    setDate(today);
  }, []);

  const selDoctorObj = doctors.find(d => d._id === selDoc);

  const handleSubmit = async (e) => {
    e.preventDefault();

    if (!selDoc) return setMsg({ type: 'er', text: 'Please select a doctor.' });
    if (!date) return setMsg({ type: 'er', text: 'Please select a date.' });
    if (!selSlot) return setMsg({ type: 'er', text: 'Please select a time slot.' });
    if (!symptoms.trim()) return setMsg({ type: 'er', text: 'Please describe your symptoms.' });

    setLoading(true);
    setMsg({ type: '', text: '' });

    try {
      await bookAppointment({
        doctorId: selDoc,
        appointmentDate: date,
        timeSlot: selSlot,
        symptoms
      });

      setMsg({ type: 'ok', text: '✅ Appointment booked successfully!' });
      setTimeout(() => navigate('/appointments'), 1500);
    } catch (err) {
      setMsg({ type: 'er', text: 'Booking failed. Try again.' });
    } finally {
      setLoading(false);
    }
  };

  const today = new Date().toISOString().split('T')[0];

  return (
    <div style={S.page}>
      {/* Overlay */}
      <div style={S.overlay}></div>

      <Navbar />

      <div style={S.wrap}>

        {/* Header */}
        <div style={S.header}>
          <button style={S.backBtn} onClick={() => navigate('/dashboard')}>
            ← Back
          </button>
          <div>
            <h1 style={S.title}>Book Appointment</h1>
            <p style={S.subtitle}>Schedule your visit easily</p>
          </div>
        </div>

        <div style={S.layout}>

          {/* LEFT FORM */}
          <div style={S.formCard}>

            {msg.text && (
              <div style={msg.type === 'ok' ? S.msgOk : S.msgEr}>
                {msg.text}
              </div>
            )}

            {/* Doctor */}
            <select style={S.input} value={selDoc} onChange={e => setSelDoc(e.target.value)}>
              <option value="">Select Doctor</option>
              {doctors.map(d => (
                <option key={d._id} value={d._id}>
                  {d.userId?.name} - {d.specialization}
                </option>
              ))}
            </select>

            {/* Date */}
            <input
              style={S.input}
              type="date"
              value={date}
              min={today}
              onChange={e => setDate(e.target.value)}
            />

            {/* Slots */}
            <div style={S.slots}>
              {SLOTS.map(slot => (
                <button
                  key={slot}
                  style={selSlot === slot ? S.slotActive : S.slot}
                  onClick={() => setSelSlot(slot)}
                >
                  {slot}
                </button>
              ))}
            </div>

            {/* Symptoms */}
            <textarea
              style={S.input}
              placeholder="Enter symptoms..."
              value={symptoms}
              onChange={e => setSymptoms(e.target.value)}
            />

            <button style={S.submitBtn} onClick={handleSubmit}>
              {loading ? 'Booking...' : 'Confirm Appointment'}
            </button>

          </div>

          {/* RIGHT SUMMARY */}
          <div style={S.summary}>
            {selDoctorObj ? (
              <>
                <h3>{selDoctorObj.userId?.name}</h3>
                <p>{selDoctorObj.specialization}</p>
                <p>₹{selDoctorObj.consultationFee}</p>
                <p>{date}</p>
                <p>{selSlot}</p>
              </>
            ) : (
              <p>Select doctor to see details</p>
            )}
          </div>

        </div>
      </div>
    </div>
  );
};

const S = {
  page: {
    minHeight: '100vh',
    backgroundImage: 'url("/images/hospital.png")',
    backgroundSize: 'cover',
    backgroundPosition: 'center',
    backgroundRepeat: 'no-repeat',
    backgroundAttachment: 'fixed',
    position: 'relative',
  },

  overlay: {
    position: 'absolute',
    width: '100%',
    height: '100%',
    background: 'rgba(255,255,255,0.75)',
    top: 0,
    left: 0,
    zIndex: 0,
  },

  wrap: {
    position: 'relative',
    zIndex: 1,
    padding: 20,
  },

  header: { display: 'flex', gap: 10, marginBottom: 20 },
  backBtn: { padding: 8 },

  title: { fontSize: 24, fontWeight: 'bold' },
  subtitle: { color: '#555' },

  layout: {
    display: 'grid',
    gridTemplateColumns: '2fr 1fr',
    gap: 20,
  },

  formCard: {
    background: '#fff',
    padding: 20,
    borderRadius: 10,
  },

  summary: {
    background: '#fff',
    padding: 20,
    borderRadius: 10,
  },

  input: {
    width: '100%',
    padding: 10,
    marginBottom: 10,
  },

  slots: {
    display: 'flex',
    flexWrap: 'wrap',
    gap: 10,
    marginBottom: 10,
  },

  slot: {
    padding: 8,
    border: '1px solid #ccc',
  },

  slotActive: {
    padding: 8,
    background: '#6366f1',
    color: '#fff',
  },

  submitBtn: {
    background: '#6366f1',
    color: '#fff',
    padding: 10,
    width: '100%',
    border: 'none',
  },

  msgOk: { color: 'green' },
  msgEr: { color: 'red' },
};

export default BookAppointment;
